import requests
from bs4 import BeautifulSoup

def get_price(url):
    response = requests.get(url)
    soup = BeautifulSoup(response.text, "html.parser")
    price_tag = soup.select_one(".price")
    # '29,900원' -> 29900 숫자로 변환
    price = price_tag.text.replace(",", "").replace("원", "").strip()
    return int(price)

